(function(){
 'use strict';
 const W=window,D=document;
 const $=(s,r=D)=>r.querySelector(s);
 const $$=(s,r=D)=>Array.from(r.querySelectorAll(s));
 const VERSION='V95.4';
 const NOTIF_KEY='crm_v952_notifications';
 const REM_KEY='crm_v953_reminders';
 const SETTINGS_KEY='crm_v954_notification_settings';
 const SENT_KEY='crm_v954_browser_sent_ids';
 const SUMMARY_KEY='crm_v954_daily_summary_date';
 const EVENT_KEY='crm_v954_notification_events';
 let filter='all';
 let drawerOpen=false;
 let lastUnread=-1;
 function uid(p){return p+'_'+Math.random().toString(36).slice(2,9)+'_'+Date.now().toString(36)}
 function nowISO(){return new Date().toISOString()}
 function today(){return new Date().toISOString().slice(0,10)}
 function esc(v){return String(v??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}
 function readJSON(k,d){try{const v=localStorage.getItem(k);return v?JSON.parse(v):d}catch(e){return d}}
 function writeJSON(k,v){try{localStorage.setItem(k,JSON.stringify(v))}catch(e){}}
 function getSettings(){return Object.assign({browserNotifications:false,desktopForReminders:true,desktopForAutomations:false,summaryOnOpen:true,toastEnabled:true,alertBeforeMinutes:15,drawerFilter:'all'},readJSON(SETTINGS_KEY,{}))}
 function saveSettings(s){writeJSON(SETTINGS_KEY,Object.assign(getSettings(),s||{}))}
 function getNotifs(){let arr=readJSON(NOTIF_KEY,[]);return Array.isArray(arr)?arr.map(normalizeNotif):[]}
 function saveNotifs(arr){writeJSON(NOTIF_KEY,(arr||[]).map(normalizeNotif).slice(0,220));updateBadge();patchAutomationsPage()}
 function normalizeNotif(n){n=Object.assign({},n||{});n.id=n.id||uid('notif');n.title=n.title||'Notificação';n.body=n.body||n.message||'';n.createdAt=n.createdAt||n.at||nowISO();n.read=!!n.read;n.source=n.source||'CRM';n.kind=n.kind||inferKind(n);n.priority=n.priority||inferPriority(n);return n}
 function inferKind(n){const t=(n.title+' '+n.body+' '+n.source).toLowerCase();if(t.includes('lembrete')||t.includes('retorno')||t.includes('vencido')||t.includes('próximo'))return 'reminder';if(t.includes('automação')||t.includes('regra'))return 'automation';return 'system'}
 function inferPriority(n){const t=(n.title+' '+n.body).toLowerCase();if(t.includes('vencido')||t.includes('erro')||t.includes('perdido'))return 'Alta';if(t.includes('próximo')||t.includes('proposta'))return 'Média';return 'Normal'}
 function addNotification(title,body,opts){opts=opts||{};const arr=getNotifs();const item=normalizeNotif({id:uid('notif'),title,body,leadId:opts.leadId||'',source:opts.source||'Notificações V95.4',kind:opts.kind||'system',priority:opts.priority||'Normal',createdAt:nowISO(),read:false});arr.unshift(item);saveNotifs(arr);toast(title,body);maybeBrowserNotify(item);logEvent('created',item);return item}
 function getReminders(){const arr=readJSON(REM_KEY,[]);return Array.isArray(arr)?arr:[]}
 function isOverdue(r){if(!r||r.status==='done')return false;const d=String(r.dueDate||'');if(!d)return false;if(d<today())return true;if(d===today()){const p=String(r.dueTime||'23:59').split(':');const m=Number(p[0]||0)*60+Number(p[1]||0);const n=new Date();const now=n.getHours()*60+n.getMinutes();return m<now}return false}
 function isToday(r){return r&&r.status!=='done'&&String(r.dueDate||'')===today()}
 function isSoon(r){if(!isToday(r))return false;const p=String(r.dueTime||'23:59').split(':');const m=Number(p[0]||0)*60+Number(p[1]||0);const n=new Date();const now=n.getHours()*60+n.getMinutes();return m>=now&&m<=now+Number(getSettings().alertBeforeMinutes||15)}
 function fmtDate(v){try{return new Date(v).toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}catch(e){return String(v||'')}}
 function fmtDateOnly(v){try{return new Date(v+'T00:00:00').toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit'})}catch(e){return String(v||'')}}
 function stats(){const n=getNotifs();const r=getReminders();return {total:n.length,unread:n.filter(x=>!x.read).length,reminder:n.filter(x=>x.kind==='reminder').length,automation:n.filter(x=>x.kind==='automation').length,system:n.filter(x=>x.kind==='system').length,overdue:r.filter(isOverdue).length,soon:r.filter(isSoon).length,today:r.filter(isToday).length,browser:browserStatus()}}
 function browserStatus(){if(!('Notification' in W))return 'Indisponível';if(Notification.permission==='granted')return 'Permitida';if(Notification.permission==='denied')return 'Bloqueada';return 'Pendente'}
 function filteredNotifs(){const arr=getNotifs();if(filter==='unread')return arr.filter(x=>!x.read);if(filter==='reminders')return arr.filter(x=>x.kind==='reminder');if(filter==='automations')return arr.filter(x=>x.kind==='automation');if(filter==='system')return arr.filter(x=>x.kind==='system');return arr}
 function iconFor(n){if(n.kind==='reminder')return '⏰';if(n.kind==='automation')return '⚡';if(n.priority==='Alta')return '🚨';return '🔔'}
 function priorityClass(p){p=String(p||'').toLowerCase();if(p.includes('alta')||p.includes('urgente'))return 'red';if(p.includes('média')||p.includes('media'))return 'warn';return 'ok'}
 function bellHTML(){const st=stats();return `<span class="v954-bell-host"><button class="v954-bell" type="button" data-v954-open-notifs title="Abrir notificações" aria-label="Abrir notificações"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 8a6 6 0 0 0-12 0c0 7-3 7-3 9h18c0-2-3-2-3-9"/><path d="M13.73 21a2 2 0 0 1-3.46 0"/></svg></button><span class="v954-bell-count ${st.unread?'':'zero'}" data-v954-count>${st.unread}</span></span>`}
 function ensureBell(){let host=$('[data-v954-bell-root]');if(!host){host=D.createElement('span');host.dataset.v954BellRoot='1';const target=$('.topbar-actions');if(target){target.appendChild(host)}else{host.className='v954-fixed-bell';D.body.appendChild(host)}}host.innerHTML=bellHTML()}
 function updateBadge(){const st=stats();$$('[data-v954-count]').forEach(el=>{el.textContent=st.unread;el.classList.toggle('zero',!st.unread)});const nav=$('[data-view="automacoes"] .nav-badge')||$('[data-view="automacoes"] .badge');if(nav)nav.textContent=st.unread||''}
 function drawerShell(){let backdrop=$('[data-v954-backdrop]');let drawer=$('[data-v954-drawer]');if(!backdrop){backdrop=D.createElement('div');backdrop.className='v954-drawer-backdrop';backdrop.dataset.v954Backdrop='1';D.body.appendChild(backdrop)}if(!drawer){drawer=D.createElement('aside');drawer.className='v954-drawer';drawer.dataset.v954Drawer='1';drawer.setAttribute('aria-label','Centro de notificações');D.body.appendChild(drawer)}return {backdrop,drawer}}
 function renderDrawer(){const {backdrop,drawer}=drawerShell();const st=stats();const list=filteredNotifs().slice(0,60);drawer.innerHTML=`<div class="v954-drawer-head"><div><h2 class="v954-drawer-title">Centro de notificações</h2><p class="v954-drawer-sub">Alertas de lembretes, automações e ações importantes do CRM.</p></div><button class="v954-icon-btn" type="button" data-v954-close title="Fechar">×</button></div><div class="v954-drawer-body"><section class="v954-summary-grid"><div class="v954-summary-card"><b>${st.unread}</b><span>Não lidas</span></div><div class="v954-summary-card"><b>${st.today}</b><span>Lembretes hoje</span></div><div class="v954-summary-card"><b>${st.overdue}</b><span>Vencidos</span></div></section><div class="v954-filter-row">${filterButton('all','Todas')} ${filterButton('unread','Não lidas')} ${filterButton('reminders','Lembretes')} ${filterButton('automations','Automações')} ${filterButton('system','Sistema')}</div><div class="v954-actions"><button class="v954-btn primary" type="button" data-v954-check-now>Verificar agora</button><button class="v954-btn" type="button" data-v954-mark-all>Marcar lidas</button><button class="v954-btn" type="button" data-v954-open-automacoes>Abrir Automações</button><button class="v954-btn warn" type="button" data-v954-browser-permission>Permitir navegador</button></div>${browserBox()}<section class="v954-notif-list">${list.length?list.map(notifCard).join(''):'<div class="v954-empty">Nenhuma notificação nesse filtro.</div>'}</section></div>`;backdrop.classList.toggle('open',drawerOpen);drawer.classList.toggle('open',drawerOpen)}
 function filterButton(id,label){return `<button class="v954-filter ${filter===id?'active':''}" type="button" data-v954-filter="${id}">${label}</button>`}
 function browserBox(){const st=browserStatus();const cls=st==='Permitida'?'':'off';return `<div class="v954-perm-box ${cls}"><div><b>Notificação do navegador: ${esc(st)}</b><p class="v954-muted">Funciona melhor com o CRM aberto. Para lembrar com o navegador fechado, depois podemos transformar o CRM em PWA com backend/push.</p></div><button class="v954-btn dark" type="button" data-v954-test-browser>Testar</button></div>`}
 function notifCard(n){return `<article class="v954-notif-card ${n.read?'':'unread'}"><div class="v954-notif-ico">${iconFor(n)}</div><div class="v954-notif-main"><b>${esc(n.title)}</b><p>${esc(n.body||'')} · ${esc(fmtDate(n.createdAt))}</p><div class="v954-notif-meta"><span class="v954-chip ${priorityClass(n.priority)}">${esc(n.priority)}</span><span class="v954-chip">${esc(n.source||'CRM')}</span><span class="v954-chip">${esc(n.kind)}</span></div></div><div class="v954-actions"><button class="v954-btn" type="button" data-v954-read="${esc(n.id)}">${n.read?'Lida':'Marcar lida'}</button>${n.leadId?`<button class="v954-btn" type="button" data-v954-open-lead="${esc(n.leadId)}">Lead</button>`:''}</div></article>`}
 function openDrawer(){drawerOpen=true;renderDrawer();markDrawerOpened()}
 function closeDrawer(){drawerOpen=false;renderDrawer()}
 function markDrawerOpened(){saveSettings({lastDrawerOpenAt:nowISO()})}
 function markAllRead(){saveNotifs(getNotifs().map(n=>Object.assign({},n,{read:true})));toast('Notificações marcadas como lidas','O contador foi zerado.');renderDrawer()}
 function markRead(id){saveNotifs(getNotifs().map(n=>n.id===id?Object.assign({},n,{read:true}):n));renderDrawer()}
 function clearRead(){saveNotifs(getNotifs().filter(n=>!n.read));toast('Notificações lidas removidas','Mantive somente as pendentes.');renderDrawer()}
 function toast(title,body){if(!getSettings().toastEnabled)return;let stack=$('[data-v954-toast-stack]');if(!stack){stack=D.createElement('div');stack.className='v954-toast-stack';stack.dataset.v954ToastStack='1';D.body.appendChild(stack)}const el=D.createElement('div');el.className='v954-toast';el.innerHTML=`<b>${esc(title)}</b>${body?`<small>${esc(body)}</small>`:''}`;stack.appendChild(el);setTimeout(()=>{el.style.opacity='0';el.style.transform='translateY(6px)';setTimeout(()=>el.remove(),240)},4200)}
 function requestBrowserPermission(){if(!('Notification' in W)){toast('Notificação indisponível','Este navegador não suporta Notification API.');return Promise.resolve(false)}return Notification.requestPermission().then(p=>{const ok=p==='granted';saveSettings({browserNotifications:ok});toast(ok?'Notificações permitidas':'Permissão não concedida',ok?'O CRM poderá mostrar avisos do navegador quando estiver aberto.':'Você ainda pode usar notificações internas no CRM.');renderDrawer();patchAutomationsPage();return ok})}
 function maybeBrowserNotify(n){const s=getSettings();if(!s.browserNotifications||!('Notification' in W)||Notification.permission!=='granted')return;const sent=readJSON(SENT_KEY,[]);if(sent.includes(n.id))return;const allow=(n.kind==='reminder'&&s.desktopForReminders)||(n.kind==='automation'&&s.desktopForAutomations)||n.kind==='system';if(!allow)return;try{new Notification(n.title,{body:n.body||'RealTalent CRM',tag:n.id,renotify:false});sent.unshift(n.id);writeJSON(SENT_KEY,sent.slice(0,250))}catch(e){}
 }
 function bridgeExistingToBrowser(){const s=getSettings();if(!s.browserNotifications||!('Notification' in W)||Notification.permission!=='granted')return;getNotifs().filter(n=>!n.read).slice(0,5).forEach(maybeBrowserNotify)}
 function checkReminders(){let count=0;const rem=getReminders();rem.forEach(r=>{if(!r||r.status==='done')return;if((isOverdue(r)||isSoon(r))&&!r.v954NotifiedAt&&!r.notifiedAt){const title=(isOverdue(r)?'Lembrete vencido: ':'Lembrete próximo: ')+(r.title||'Ação pendente');const body=(r.leadName?String(r.leadName)+' · ':'')+(r.dueDate?fmtDateOnly(r.dueDate):'')+' '+(r.dueTime||'');addNotification(title,body,{leadId:r.leadId||'',kind:'reminder',priority:isOverdue(r)?'Alta':'Média'});r.v954NotifiedAt=nowISO();count++}});if(count){writeJSON(REM_KEY,rem)}return count}
 function dailySummary(force){const s=getSettings();if(!s.summaryOnOpen&&!force)return 0;const last=readJSON(SUMMARY_KEY,'');if(last===today()&&!force)return 0;const st=stats();if(st.today||st.overdue||st.soon){addNotification('Resumo do dia',`${st.today} lembrete(s) hoje, ${st.overdue} vencido(s) e ${st.soon} próximo(s).`,{kind:'system',priority:st.overdue?'Alta':'Normal'});writeJSON(SUMMARY_KEY,today());return 1}return 0}
 function checkNow(){let c=0;try{if(W.CRMV953RemindersCenter&&typeof W.CRMV953RemindersCenter.checkDueReminders==='function')c+=Number(W.CRMV953RemindersCenter.checkDueReminders(false)||0)}catch(e){}c+=checkReminders();c+=dailySummary(true);bridgeExistingToBrowser();toast('Verificação concluída',`${c} alerta(s) gerados ou enviados.`);renderDrawer();patchAutomationsPage()}
 function openAutomacoes(){location.hash='#automacoes';const btn=$('[data-view="automacoes"]');if(btn)btn.click();setTimeout(()=>{patchAutomationsPage();closeDrawer()},120)}
 function openLead(id){if(!id){toast('Sem lead vinculado','Essa notificação não aponta para um lead específico.');return}try{if(W.CRMV94Official&&typeof W.CRMV94Official.openLead==='function'){W.CRMV94Official.openLead(id);closeDrawer();return}}catch(e){}location.hash='#leads';const b=$('[data-view="leads"]');if(b)b.click();toast('Lead vinculado',id);closeDrawer()}
 function logEvent(kind,item){const arr=readJSON(EVENT_KEY,[]);arr.unshift({id:uid('ev'),kind,at:nowISO(),title:item&&item.title||''});writeJSON(EVENT_KEY,arr.slice(0,160))}
 function automationPanelHTML(){const st=stats();const top=getNotifs().filter(n=>!n.read).slice(0,4);return `<section class="v954-automations-panel" data-v954-embedded><div class="v954-panel-head"><div><h2 class="v954-panel-title">Centro de notificações</h2><p class="v954-muted">Sininho global para lembretes, automações e alertas importantes. As notificações internas funcionam dentro do CRM; as do navegador pedem permissão.</p></div><div class="v954-actions"><button class="v954-btn primary" type="button" data-v954-open-notifs>Abrir sino</button><button class="v954-btn" type="button" data-v954-check-now>Verificar agora</button><button class="v954-btn warn" type="button" data-v954-browser-permission>Permitir navegador</button></div></div><div class="v954-panel-grid"><div class="v954-kpi"><b>${st.unread}</b><span>Não lidas</span></div><div class="v954-kpi"><b>${st.today}</b><span>Lembretes hoje</span></div><div class="v954-kpi"><b>${st.overdue}</b><span>Vencidos</span></div><div class="v954-kpi"><b>${esc(st.browser)}</b><span>Navegador</span></div></div>${browserBox()}<div class="v954-mini-list">${top.length?top.map(n=>`<div class="v954-mini-notif"><div><strong>${esc(n.title)}</strong><small>${esc(n.body||'')} · ${esc(fmtDate(n.createdAt))}</small></div><button class="v954-btn" type="button" data-v954-read="${esc(n.id)}">Lida</button></div>`).join(''):'<div class="v954-empty">Nenhuma notificação pendente agora.</div>'}</div><div class="v954-settings-grid"><label>Minutos antes do lembrete<input class="v954-field" type="number" min="1" max="240" data-v954-setting="alertBeforeMinutes" value="${esc(getSettings().alertBeforeMinutes)}"></label><label class="v954-switch"><input type="checkbox" data-v954-setting-check="summaryOnOpen" ${getSettings().summaryOnOpen?'checked':''}> Resumo ao abrir o CRM</label><label class="v954-switch"><input type="checkbox" data-v954-setting-check="toastEnabled" ${getSettings().toastEnabled?'checked':''}> Mostrar avisos no canto</label><label class="v954-switch"><input type="checkbox" data-v954-setting-check="desktopForReminders" ${getSettings().desktopForReminders?'checked':''}> Enviar lembretes para navegador</label></div><div class="v954-actions"><button class="v954-btn dark" type="button" data-v954-save-settings>Salvar preferências</button><button class="v954-btn" type="button" data-v954-test-internal>Criar aviso de teste</button><button class="v954-btn danger" type="button" data-v954-clear-read>Limpar lidas</button></div></section>`}
 function patchAutomationsPage(){const sec=$('#automacoes');if(!sec)return;if(!sec.classList.contains('active')&&!(location.hash||'').includes('automacoes'))return;if(sec.querySelector('[data-v954-embedded]'))return;const firstMain=sec.querySelector('.v953-wrap main')||sec.querySelector('main');const tabs=sec.querySelector('.v953-tabs');const html=automationPanelHTML();if(tabs)tabs.insertAdjacentHTML('afterend',html);else if(firstMain)firstMain.insertAdjacentHTML('beforebegin',html);else sec.insertAdjacentHTML('afterbegin',html)}
 function savePanelSettings(){const sec=$('#automacoes');const s={};$$('[data-v954-setting]',sec).forEach(i=>{s[i.dataset.v954Setting]=i.type==='number'?Number(i.value||0):i.value});$$('[data-v954-setting-check]',sec).forEach(i=>{s[i.dataset.v954SettingCheck]=!!i.checked});saveSettings(s);toast('Preferências salvas','As notificações foram atualizadas.');patchAutomationsPage();renderDrawer()}
 function bind(){if(W.__crmV954Bound)return;W.__crmV954Bound=true;D.addEventListener('click',e=>{const t=e.target.closest('button,[data-v954-open-notifs]');if(!t)return;if(t.hasAttribute('data-v954-open-notifs')){openDrawer();return}if(t.hasAttribute('data-v954-close')){closeDrawer();return}if(t.dataset.v954Filter){filter=t.dataset.v954Filter;saveSettings({drawerFilter:filter});renderDrawer();return}if(t.hasAttribute('data-v954-mark-all')){markAllRead();return}if(t.dataset.v954Read){markRead(t.dataset.v954Read);patchAutomationsPage();return}if(t.hasAttribute('data-v954-clear-read')){clearRead();return}if(t.hasAttribute('data-v954-check-now')){checkNow();return}if(t.hasAttribute('data-v954-browser-permission')){requestBrowserPermission();return}if(t.hasAttribute('data-v954-test-browser')){if(!('Notification' in W)){toast('Indisponível','Este navegador não suporta notificação do sistema.');return}if(Notification.permission!=='granted'){requestBrowserPermission().then(ok=>{if(ok)maybeBrowserNotify(addNotification('Teste de notificação','Esse aviso veio do navegador.',{kind:'system'}))});return}maybeBrowserNotify(addNotification('Teste de notificação','Esse aviso veio do navegador.',{kind:'system'}));return}if(t.hasAttribute('data-v954-test-internal')){addNotification('Aviso de teste','Notificação interna criada manualmente.',{kind:'system'});renderDrawer();return}if(t.hasAttribute('data-v954-open-automacoes')){openAutomacoes();return}if(t.dataset.v954OpenLead){openLead(t.dataset.v954OpenLead);return}if(t.hasAttribute('data-v954-save-settings')){savePanelSettings();return}});const bd=$('[data-v954-backdrop]');D.addEventListener('click',e=>{if(e.target&&e.target.matches('[data-v954-backdrop]'))closeDrawer()});D.addEventListener('keydown',e=>{if(e.key==='Escape'&&drawerOpen)closeDrawer()})}
 function wrapRenders(){try{if(W.CRMV953RemindersCenter&&!W.CRMV953RemindersCenter.__v954Wrapped&&typeof W.CRMV953RemindersCenter.render==='function'){const old=W.CRMV953RemindersCenter.render;W.CRMV953RemindersCenter.render=function(){const r=old.apply(this,arguments);setTimeout(patchAutomationsPage,30);return r};W.CRMV953RemindersCenter.__v954Wrapped=true}}catch(e){}try{if(W.CRMV95Automations&&!W.CRMV95Automations.__v954Wrapped&&typeof W.CRMV95Automations.render==='function'){const old2=W.CRMV95Automations.render;W.CRMV95Automations.render=function(){const r=old2.apply(this,arguments);setTimeout(patchAutomationsPage,30);return r};W.CRMV95Automations.__v954Wrapped=true}}catch(e){}try{if(typeof W.renderAutomations==='function'&&!W.renderAutomations.__v954Wrapped){const old3=W.renderAutomations;const f=function(){const r=old3.apply(this,arguments);setTimeout(patchAutomationsPage,30);return r};f.__v954Wrapped=true;W.renderAutomations=f}}catch(e){}}
 function monitorUnread(){const u=stats().unread;if(u!==lastUnread){lastUnread=u;updateBadge();if(drawerOpen)renderDrawer();patchAutomationsPage()}}
 function boot(){D.body&&D.body.classList.add('v954-notifications-ready');filter=getSettings().drawerFilter||'all';ensureBell();drawerShell();bind();wrapRenders();updateBadge();checkReminders();dailySummary(false);bridgeExistingToBrowser();setInterval(()=>{checkReminders();bridgeExistingToBrowser();monitorUnread()},60000);setInterval(monitorUnread,3500);/* V97.1: MutationObserver V95.4 removido para evitar loop infinito. */setTimeout(()=>{patchAutomationsPage();renderDrawer()},450);W.CRMV954Notifications={version:VERSION,addNotification,openDrawer,closeDrawer,checkNow,markAllRead,getNotifs,saveNotifs,requestBrowserPermission,patchAutomationsPage};if(W.CRMV94Official&&W.CRMV94Official.map)W.CRMV94Official.map.automacoes='V95.4 Centro de Notificações'}
 if(D.readyState==='loading')D.addEventListener('DOMContentLoaded',boot,{once:true});else boot();
})();
